"use client";

import * as React from "react";
import { ArrowLeft, ArrowRight } from "lucide-react";
import {
  motion,
  type MotionValue,
  useMotionValue,
  useMotionValueEvent,
  useReducedMotion,
  useSpring,
  useTransform,
} from "motion/react";

import {
  DepthCameraScene,
  type DepthCameraLayer,
  type DepthCameraSceneProps,
} from "@/components/experience/depth-camera-scene";
import { HorizontalTrack } from "@/components/experience/horizontal-track";
import { Button } from "@/components/ui/button";
import { cn } from "@/lib/utils";

export type CinematicWorldCatalog = {
  heading: React.ReactNode;
  items: React.ReactNode[];
  label: string;
  eyebrow?: React.ReactNode;
  itemClassName?: string | ((index: number) => string | undefined);
  trackClassName?: string;
};

export type CinematicWorldSceneProps = Omit<
  DepthCameraSceneProps,
  "backOverlay" | "frontOverlay"
> & {
  catalog: CinematicWorldCatalog;
  chrome?: React.ReactNode;
  intro: React.ReactNode;
  rearNarrative?: React.ReactNode | ((progress: MotionValue<number>) => React.ReactNode);
  frontNarrative?: React.ReactNode | ((progress: MotionValue<number>) => React.ReactNode);
  layers: DepthCameraLayer[];
  /** Accessible name for the catalog region that owns ArrowLeft/ArrowRight frame navigation. */
  catalogRegionLabel?: string;
  /** Aria label for the previous-frame button. */
  previousFrameLabel?: string;
  /** Aria label for the next-frame button. */
  nextFrameLabel?: string;
};

function resolveNarrative(
  narrative: CinematicWorldSceneProps["rearNarrative"] | CinematicWorldSceneProps["frontNarrative"],
  progress: MotionValue<number>,
) {
  return typeof narrative === "function" ? narrative(progress) : narrative;
}

function CinematicBackOverlay({
  intro,
  narrative,
  progress,
}: {
  intro: React.ReactNode;
  narrative?: CinematicWorldSceneProps["rearNarrative"];
  progress: MotionValue<number>;
}) {
  const introOpacity = useTransform(progress, [0, 0.08, 0.19, 0.27], [1, 1, 0.45, 0]);
  const introY = useTransform(progress, [0, 0.27], [0, -110]);
  const narrativeOpacity = useTransform(progress, [0.14, 0.21, 0.33, 0.43], [0, 1, 1, 0]);
  const narrativeY = useTransform(progress, [0.14, 0.28, 0.43], [110, 0, -120]);
  const narrativeScale = useTransform(progress, [0.14, 0.33, 0.43], [0.94, 1.03, 1.1]);
  return (
    <>
      <motion.div className="absolute inset-0" style={{ opacity: introOpacity, y: introY }}>
        {intro}
      </motion.div>
      {narrative ? (
        <motion.div
          className="absolute inset-0"
          style={{ opacity: narrativeOpacity, y: narrativeY, scale: narrativeScale }}
        >
          {resolveNarrative(narrative, progress)}
        </motion.div>
      ) : null}
    </>
  );
}

function CinematicFrontOverlay({
  catalog,
  catalogRegionLabel,
  chrome,
  narrative,
  nextFrameLabel,
  previousFrameLabel,
  progress,
}: {
  catalog: CinematicWorldCatalog;
  catalogRegionLabel: string;
  chrome?: React.ReactNode;
  narrative?: CinematicWorldSceneProps["frontNarrative"];
  nextFrameLabel: string;
  previousFrameLabel: string;
  progress: MotionValue<number>;
}) {
  const target = useMotionValue(0);
  const spring = useSpring(target, { stiffness: 160, damping: 32, mass: 0.28 });
  const reducedMotion = useReducedMotion();
  const trackProgress = reducedMotion ? target : spring;
  const [activeIndex, setActiveIndex] = React.useState(0);
  const [catalogInteractive, setCatalogInteractive] = React.useState(false);
  const chromeOpacity = useTransform(progress, [0.52, 0.66], [1, 0]);
  const narrativeOpacity = useTransform(progress, [0.7, 0.75, 0.82, 0.88], [0, 1, 1, 0]);
  const narrativeY = useTransform(progress, [0.7, 0.77, 0.88], [70, 0, -80]);
  const catalogOpacity = useTransform(progress, [0.88, 0.95, 1], [0, 0.76, 1]);
  const catalogY = useTransform(progress, [0.88, 1], ["14vh", "0vh"]);
  const catalogScale = useTransform(progress, [0.88, 1], [0.96, 1]);
  const scrimOpacity = useTransform(progress, [0.87, 0.99], [0, 0.84]);

  useMotionValueEvent(progress, "change", (value) => {
    const interactive = value >= 0.9;
    setCatalogInteractive((current) => current === interactive ? current : interactive);
    if (value < 0.72 && target.get() !== 0) {
      target.set(0);
      setActiveIndex(0);
    }
  });

  const goTo = (nextIndex: number) => {
    const lastIndex = Math.max(0, catalog.items.length - 1);
    const resolved = Math.max(0, Math.min(lastIndex, nextIndex));
    setActiveIndex(resolved);
    target.set(lastIndex === 0 ? 0 : resolved / lastIndex);
  };

  const handleCatalogKeyDown = (event: React.KeyboardEvent<HTMLDivElement>) => {
    if (!catalogInteractive) return;
    if (event.key === "ArrowLeft") {
      event.preventDefault();
      goTo(activeIndex - 1);
    }
    if (event.key === "ArrowRight") {
      event.preventDefault();
      goTo(activeIndex + 1);
    }
  };

  return (
    <>
      {chrome ? (
        <motion.div aria-hidden className="absolute inset-x-0 top-0 z-20" style={{ opacity: chromeOpacity }}>
          {chrome}
        </motion.div>
      ) : null}
      {narrative ? (
        <motion.div className="absolute inset-0 z-10" style={{ opacity: narrativeOpacity, y: narrativeY }}>
          {resolveNarrative(narrative, progress)}
        </motion.div>
      ) : null}
      <motion.div
        aria-hidden
        className="absolute inset-0 z-20 bg-[linear-gradient(180deg,rgba(5,9,12,.18),rgba(5,9,12,.94))]"
        style={{ opacity: scrimOpacity }}
      />
      <motion.div
        aria-hidden={!catalogInteractive}
        role="group"
        aria-label={catalogRegionLabel}
        tabIndex={catalogInteractive ? 0 : undefined}
        onKeyDown={handleCatalogKeyDown}
        data-cinematic-catalog
        className={cn(
          "absolute inset-0 z-30 flex flex-col overflow-hidden pb-6 pt-24 text-white",
          catalogInteractive ? "pointer-events-auto" : "pointer-events-none",
        )}
        style={{ opacity: catalogOpacity, y: catalogY, scale: catalogScale }}
      >
        <div className="flex items-end justify-between gap-6 px-5 sm:px-[5vw]">
          <div>
            {catalog.eyebrow ? (
              <div className="text-[0.68rem] font-semibold uppercase tracking-[0.22em] text-white/52">
                {catalog.eyebrow}
              </div>
            ) : null}
            <div className="mt-3 text-[clamp(2.7rem,6vw,5.8rem)] font-semibold leading-[0.86] tracking-[-0.065em]">
              {catalog.heading}
            </div>
          </div>
          <div className="flex shrink-0 gap-2">
            <Button type="button" variant="outline" size="icon" className="rounded-full border-white/20 bg-black/15 text-white backdrop-blur-md hover:bg-white hover:text-black" aria-label={previousFrameLabel} tabIndex={catalogInteractive ? undefined : -1} disabled={!catalogInteractive || activeIndex === 0} onClick={() => goTo(activeIndex - 1)}>
              <ArrowLeft aria-hidden />
            </Button>
            <Button type="button" variant="outline" size="icon" className="rounded-full border-white/20 bg-black/15 text-white backdrop-blur-md hover:bg-white hover:text-black" aria-label={nextFrameLabel} tabIndex={catalogInteractive ? undefined : -1} disabled={!catalogInteractive || catalog.items.length <= 1 || activeIndex === catalog.items.length - 1} onClick={() => goTo(activeIndex + 1)}>
              <ArrowRight aria-hidden />
            </Button>
          </div>
        </div>
        <div className="mt-6 min-h-0 flex-1">
          <HorizontalTrack label={catalog.label} progress={trackProgress} itemClassName={catalog.itemClassName} trackClassName={catalog.trackClassName} progressClassName="text-white">
            {catalog.items}
          </HorizontalTrack>
        </div>
      </motion.div>
    </>
  );
}

/** A composed Advanced recipe. Use `DepthCameraScene` directly for custom timelines. */
export function CinematicWorldScene({
  catalog,
  catalogRegionLabel = "Frame catalog",
  chrome,
  frontNarrative,
  intro,
  nextFrameLabel = "Next frame",
  previousFrameLabel = "Previous frame",
  rearNarrative,
  ...props
}: CinematicWorldSceneProps) {
  return (
    <DepthCameraScene
      {...props}
      backOverlay={(progress) => (
        <CinematicBackOverlay intro={intro} narrative={rearNarrative} progress={progress} />
      )}
      frontOverlay={(progress) => (
        <CinematicFrontOverlay
          catalog={catalog}
          catalogRegionLabel={catalogRegionLabel}
          chrome={chrome}
          narrative={frontNarrative}
          nextFrameLabel={nextFrameLabel}
          previousFrameLabel={previousFrameLabel}
          progress={progress}
        />
      )}
    />
  );
}

"use client";

import * as React from "react";
import { type MotionValue, useMotionValue, useReducedMotion } from "motion/react";
import * as THREE from "three";

import { cn } from "@/lib/utils";
import {
  damp,
  mix,
  resolveKeyframes,
  sortKeyframes,
  useHydrated,
  useMediaQuery,
} from "@/components/experience/experience-runtime";
import { useElementScrollProgress } from "@/components/experience/use-element-scroll-progress";
import {
  useWebGLStage,
  type WebGLStageContext,
  type WebGLStageHandle,
} from "@/components/experience/use-webgl-stage";

export type DepthCameraLayerKeyframe = {
  at: number;
  x?: number;
  y?: number;
  z?: number;
  scale?: number;
  opacity?: number;
};

export type DepthCameraBounds = {
  /** Normalized placement inside the registered master canvas. */
  x: number;
  y: number;
  width: number;
  height: number;
};

export type DepthCameraWorldEffectKeyframe = {
  at: number;
  blur?: number;
  brightness?: number;
  saturation?: number;
};

export type DepthCameraLayer = {
  id: string;
  src: string;
  mobileSrc?: string;
  plane: "back" | "front";
  depth: number;
  opacity?: number;
  /**
   * Render this plate without alpha blending. Use for the fully covering
   * backdrop plate so it composites as a solid base instead of blending.
   * Front-plane layers always blend (they sit over the DOM sandwich).
   */
  opaque?: boolean;
  /** Purely decorative plate that low-power devices skip to save a texture and a full-screen blend pass. */
  dropOnLowPower?: boolean;
  /**
   * Places a trimmed high-resolution texture inside the registered canvas.
   * This avoids shipping a mostly-transparent 4K full-canvas plate.
   */
  bounds?: DepthCameraBounds;
  /** Aspect ratio of the registered master canvas used by `bounds`. */
  canvasAspect?: number;
  timeline?: DepthCameraLayerKeyframe[];
};

export type DepthCameraBeat = {
  at: number;
  x?: number;
  y?: number;
  z: number;
  lookX?: number;
  lookY?: number;
  fov?: number;
};

export type DepthCameraSceneProps = Omit<React.ComponentProps<"section">, "children"> & {
  label: string;
  layers: DepthCameraLayer[];
  poster: string;
  mobilePoster?: string;
  camera?: DepthCameraBeat[];
  scrollScreens?: number;
  smoothing?: number;
  maxDpr?: number;
  pointerStrength?: number;
  progress?: MotionValue<number>;
  /** Unblurred continuity layer rendered over the world pass and under copy/subjects. */
  persistentBackdrop?: React.ReactNode;
  /** CSS post effects applied only to the back WebGL world pass. */
  worldEffects?: DepthCameraWorldEffectKeyframe[];
  backOverlay?: React.ReactNode | ((progress: MotionValue<number>) => React.ReactNode);
  frontOverlay?: React.ReactNode | ((progress: MotionValue<number>) => React.ReactNode);
  reducedMotionFallback?: React.ReactNode;
  stageClassName?: string;
  onProgressChange?: (progress: number) => void;
  mobileBreakpoint?: number;
};

type PlaneRecord = {
  layer: DepthCameraLayer;
  frames: DepthCameraLayerKeyframe[];
  mesh: THREE.Mesh<THREE.PlaneGeometry, THREE.MeshBasicMaterial>;
  textureAspect: number;
};

const DEFAULT_CAMERA: DepthCameraBeat[] = [
  { at: 0, x: 0, y: 0, z: 9, lookX: 0, lookY: 0, fov: 46 },
  { at: 0.18, x: 0, y: 0, z: 8.1, lookX: 0, lookY: 0, fov: 45 },
  { at: 0.43, x: 0.08, y: 0.03, z: 6.25, lookX: 0.02, lookY: 0, fov: 43 },
  { at: 0.68, x: 0.26, y: 0.08, z: 4.35, lookX: 0.1, lookY: 0.01, fov: 41 },
  { at: 0.88, x: 0.58, y: 0.12, z: 3.15, lookX: 0.26, lookY: 0.02, fov: 39 },
  { at: 1, x: 0.72, y: 0.15, z: 2.72, lookX: 0.34, lookY: 0.02, fov: 38 },
];

const DEFAULT_TIMELINE: DepthCameraLayerKeyframe[] = [{ at: 0 }, { at: 1 }];
const DEFAULT_WORLD_EFFECTS: DepthCameraWorldEffectKeyframe[] = [
  { at: 0, blur: 0, brightness: 1, saturation: 1 },
  { at: 1, blur: 0, brightness: 1, saturation: 1 },
];

function resolveNumber(value: number | undefined, fallback: number) {
  return value ?? fallback;
}

function sampleCamera(frames: DepthCameraBeat[], progress: number) {
  const { from, to, mix: amount } = resolveKeyframes(frames, progress);
  return {
    x: mix(resolveNumber(from.x, 0), resolveNumber(to.x, 0), amount),
    y: mix(resolveNumber(from.y, 0), resolveNumber(to.y, 0), amount),
    z: mix(from.z, to.z, amount),
    lookX: mix(resolveNumber(from.lookX, 0), resolveNumber(to.lookX, 0), amount),
    lookY: mix(resolveNumber(from.lookY, 0), resolveNumber(to.lookY, 0), amount),
    fov: mix(resolveNumber(from.fov, 46), resolveNumber(to.fov, 46), amount),
  };
}

function sampleLayer(record: PlaneRecord, progress: number) {
  const baseOpacity = record.layer.opacity ?? 1;
  const { from, to, mix: amount } = resolveKeyframes(record.frames, progress);
  return {
    x: mix(resolveNumber(from.x, 0), resolveNumber(to.x, 0), amount),
    y: mix(resolveNumber(from.y, 0), resolveNumber(to.y, 0), amount),
    z: mix(resolveNumber(from.z, 0), resolveNumber(to.z, 0), amount),
    scale: mix(resolveNumber(from.scale, 1), resolveNumber(to.scale, 1), amount),
    opacity: mix(
      resolveNumber(from.opacity, baseOpacity),
      resolveNumber(to.opacity, baseOpacity),
      amount,
    ),
  };
}

function sampleWorldEffect(frames: DepthCameraWorldEffectKeyframe[], progress: number) {
  const { from, to, mix: amount } = resolveKeyframes(frames, progress);
  return {
    blur: mix(resolveNumber(from.blur, 0), resolveNumber(to.blur, 0), amount),
    brightness: mix(resolveNumber(from.brightness, 1), resolveNumber(to.brightness, 1), amount),
    saturation: mix(resolveNumber(from.saturation, 1), resolveNumber(to.saturation, 1), amount),
  };
}

function renderOverlay(
  overlay: DepthCameraSceneProps["backOverlay"] | DepthCameraSceneProps["frontOverlay"],
  progress: MotionValue<number>,
) {
  return typeof overlay === "function" ? overlay(progress) : overlay;
}

/**
 * A real-camera 2.5D engine for registered, full-canvas raster plates.
 * Back and front WebGL passes sandwich semantic DOM, so copy can be truly
 * occluded by the hero/foreground instead of faking depth with z-index alone.
 */
export function DepthCameraScene({
  backOverlay,
  camera = DEFAULT_CAMERA,
  className,
  frontOverlay,
  label,
  layers,
  maxDpr = 1.75,
  mobileBreakpoint = 768,
  mobilePoster,
  onPointerLeave,
  onPointerMove,
  onProgressChange,
  persistentBackdrop,
  pointerStrength = 0.11,
  poster,
  progress: controlledProgress,
  reducedMotionFallback,
  scrollScreens = 6,
  smoothing = 10,
  stageClassName,
  style,
  worldEffects = DEFAULT_WORLD_EFFECTS,
  ...props
}: DepthCameraSceneProps) {
  const rootRef = React.useRef<HTMLElement>(null);
  const stageRef = React.useRef<HTMLDivElement>(null);
  const backCanvasRef = React.useRef<HTMLCanvasElement>(null);
  const frontCanvasRef = React.useRef<HTMLCanvasElement>(null);
  const pointerRef = React.useRef({ x: 0, y: 0 });
  const targetPointerRef = React.useRef({ x: 0, y: 0 });
  const smoothedRef = React.useRef(0);
  const rawProgress = useElementScrollProgress(rootRef);
  const visibleProgress = useMotionValue(0);
  const reducedMotion = useReducedMotion();
  const hydrated = useHydrated();
  const mobile = useMediaQuery(`(max-width: ${mobileBreakpoint - 0.02}px)`);
  const sceneProgress = controlledProgress ?? rawProgress;
  const prefersReducedMotion = hydrated && Boolean(reducedMotion);
  const lowPower = typeof navigator !== "undefined" && (navigator.hardwareConcurrency ?? 8) <= 4;

  // Per-frame inputs flow through a ref so identity changes never rebuild the scene.
  const runtimeRef = React.useRef({ onProgressChange, pointerStrength, sceneProgress, smoothing });
  React.useInsertionEffect(() => {
    runtimeRef.current = { onProgressChange, pointerStrength, sceneProgress, smoothing };
  });

  const layerSignature = React.useMemo(() => JSON.stringify(layers), [layers]);
  const cameraSignature = React.useMemo(() => JSON.stringify(camera), [camera]);
  const effectsSignature = React.useMemo(() => JSON.stringify(worldEffects), [worldEffects]);
  const sceneSignature = `${layerSignature}|${cameraSignature}|${effectsSignature}|${mobile ? "mobile" : "desktop"}`;

  const buildPass = (plane: DepthCameraLayer["plane"], context: WebGLStageContext): WebGLStageHandle => {
    const { renderer, markReady, markFailed, isDisposed, requestResize } = context;
    renderer.toneMapping = THREE.NoToneMapping;
    renderer.setClearColor(0x000000, 0);
    const scene = new THREE.Scene();
    const cameraFrames = sortKeyframes(camera);
    const worldEffectFrames = sortKeyframes(worldEffects);
    const initialBeat = sampleCamera(cameraFrames, 0);
    const passCamera = new THREE.PerspectiveCamera(initialBeat.fov, 1, 0.05, 100);
    passCamera.position.set(initialBeat.x, initialBeat.y, initialBeat.z);
    passCamera.lookAt(initialBeat.lookX, initialBeat.lookY, 0);
    const records: PlaneRecord[] = [];
    const passLayers = layers.filter(
      (layer) => layer.plane === plane && !(lowPower && layer.dropOnLowPower),
    );
    const loader = new THREE.TextureLoader();
    if (plane === "back") {
      smoothedRef.current = runtimeRef.current.sceneProgress.get();
    }

    Promise.all(passLayers.map(async (layer, index) => {
      const source = mobile && layer.mobileSrc ? layer.mobileSrc : layer.src;
      const texture = await loader.loadAsync(source);
      if (isDisposed()) {
        texture.dispose();
        return;
      }
      texture.colorSpace = THREE.SRGBColorSpace;
      texture.anisotropy = Math.min(8, renderer.capabilities.getMaxAnisotropy());
      texture.generateMipmaps = true;
      texture.minFilter = THREE.LinearMipmapLinearFilter;
      texture.magFilter = THREE.LinearFilter;
      const image = texture.image as HTMLImageElement;
      const textureAspect = Math.max(0.01, image.naturalWidth / Math.max(1, image.naturalHeight));
      const geometry = new THREE.PlaneGeometry(textureAspect, 1, 1, 1);
      const material = new THREE.MeshBasicMaterial({
        map: texture,
        transparent: layer.plane === "front" || !layer.opaque,
        opacity: layer.opacity ?? 1,
        depthTest: false,
        depthWrite: false,
        toneMapped: false,
      });
      const mesh = new THREE.Mesh(geometry, material);
      mesh.position.z = layer.depth;
      mesh.renderOrder = index;
      scene.add(mesh);
      records.push({
        layer,
        frames: sortKeyframes(layer.timeline?.length ? layer.timeline : DEFAULT_TIMELINE),
        mesh,
        textureAspect,
      });
    }))
      .then(() => {
        if (isDisposed()) return;
        requestResize();
        markReady();
      })
      .catch(() => markFailed());

    const applyFrame = () => {
      const progress = smoothedRef.current;
      const strength = runtimeRef.current.pointerStrength;
      const sampled = sampleCamera(cameraFrames, progress);
      const pointerX = mobile ? 0 : pointerRef.current.x * strength;
      const pointerY = mobile ? 0 : pointerRef.current.y * strength;
      passCamera.position.set(sampled.x + pointerX, sampled.y - pointerY, sampled.z);
      passCamera.fov = sampled.fov;
      passCamera.lookAt(sampled.lookX + pointerX * 0.18, sampled.lookY - pointerY * 0.12, 0);
      passCamera.updateProjectionMatrix();
      for (const record of records) {
        const sampledLayer = sampleLayer(record, progress);
        const baseScaleX = resolveNumber(record.mesh.userData.baseScaleX as number | undefined, 1);
        const baseScaleY = resolveNumber(record.mesh.userData.baseScaleY as number | undefined, 1);
        const baseX = resolveNumber(record.mesh.userData.baseX as number | undefined, 0);
        const baseY = resolveNumber(record.mesh.userData.baseY as number | undefined, 0);
        record.mesh.position.set(
          baseX + sampledLayer.x,
          baseY + sampledLayer.y,
          record.layer.depth + sampledLayer.z,
        );
        record.mesh.scale.set(
          baseScaleX * sampledLayer.scale,
          baseScaleY * sampledLayer.scale,
          1,
        );
        record.mesh.material.opacity = sampledLayer.opacity;
      }
      if (plane === "back" && backCanvasRef.current) {
        const effect = sampleWorldEffect(worldEffectFrames, progress);
        backCanvasRef.current.style.filter = `blur(${effect.blur.toFixed(2)}px) brightness(${effect.brightness.toFixed(3)}) saturate(${effect.saturation.toFixed(3)})`;
        backCanvasRef.current.style.transform = `scale(${(1 + effect.blur * 0.0018).toFixed(4)})`;
      }
      renderer.render(scene, passCamera);
    };

    return {
      onResize: (width, height) => {
        const viewportAspect = width / Math.max(1, height);
        passCamera.aspect = viewportAspect;
        passCamera.updateProjectionMatrix();
        const verticalFov = THREE.MathUtils.degToRad(initialBeat.fov);
        for (const record of records) {
          const distance = Math.max(0.1, initialBeat.z - record.layer.depth);
          const visibleHeight = 2 * Math.tan(verticalFov / 2) * distance;
          const visibleWidth = visibleHeight * viewportAspect;
          if (record.layer.bounds) {
            const bounds = record.layer.bounds;
            const canvasAspect = record.layer.canvasAspect ?? 16 / 9;
            const fullCanvasFit = Math.max(visibleHeight, visibleWidth / canvasAspect) * 1.035;
            record.mesh.userData.baseScaleX =
              (fullCanvasFit * canvasAspect * bounds.width) / record.textureAspect;
            record.mesh.userData.baseScaleY = fullCanvasFit * bounds.height;
            record.mesh.userData.baseX =
              (bounds.x + bounds.width / 2 - 0.5) * fullCanvasFit * canvasAspect;
            record.mesh.userData.baseY =
              (0.5 - bounds.y - bounds.height / 2) * fullCanvasFit;
          } else {
            const fit = Math.max(visibleHeight, visibleWidth / record.textureAspect) * 1.035;
            record.mesh.userData.baseScaleX = fit;
            record.mesh.userData.baseScaleY = fit;
            record.mesh.userData.baseX = 0;
            record.mesh.userData.baseY = 0;
          }
        }
        applyFrame();
      },
      onFrame: (delta) => {
        // The back pass is the sole writer of shared progress/pointer state;
        // the front pass reads the same refs, so both passes stay registered.
        if (plane === "back") {
          const runtime = runtimeRef.current;
          smoothedRef.current = damp(smoothedRef.current, runtime.sceneProgress.get(), runtime.smoothing, delta);
          visibleProgress.set(smoothedRef.current);
          runtime.onProgressChange?.(smoothedRef.current);
          pointerRef.current.x = damp(pointerRef.current.x, targetPointerRef.current.x, 8, delta);
          pointerRef.current.y = damp(pointerRef.current.y, targetPointerRef.current.y, 8, delta);
        }
        applyFrame();
      },
      dispose: () => {
        for (const record of records) {
          record.mesh.geometry.dispose();
          record.mesh.material.map?.dispose();
          record.mesh.material.dispose();
        }
      },
    };
  };

  const stageEnabled = !prefersReducedMotion;
  const effectiveMaxDpr = lowPower ? 1.25 : maxDpr;
  const backStage = useWebGLStage({
    stageRef,
    canvasRef: backCanvasRef,
    enabled: stageEnabled,
    maxDpr: effectiveMaxDpr,
    antialias: !lowPower,
    alpha: true,
    rootMargin: "25% 0px",
    signature: sceneSignature,
    create: (context) => buildPass("back", context),
  });
  const frontStage = useWebGLStage({
    stageRef,
    canvasRef: frontCanvasRef,
    enabled: stageEnabled,
    maxDpr: effectiveMaxDpr,
    antialias: !lowPower,
    alpha: true,
    rootMargin: "25% 0px",
    signature: sceneSignature,
    create: (context) => buildPass("front", context),
  });
  const ready = backStage.ready && frontStage.ready;
  const failed = backStage.failed || frontStage.failed;

  const handlePointerMove = (event: React.PointerEvent<HTMLElement>) => {
    if (!mobile && event.pointerType !== "touch") {
      const rect = event.currentTarget.getBoundingClientRect();
      targetPointerRef.current.x = (event.clientX - rect.left) / Math.max(1, rect.width) - 0.5;
      targetPointerRef.current.y = (event.clientY - rect.top) / Math.max(1, rect.height) - 0.5;
    }
    onPointerMove?.(event);
  };
  const handlePointerLeave = (event: React.PointerEvent<HTMLElement>) => {
    targetPointerRef.current = { x: 0, y: 0 };
    onPointerLeave?.(event);
  };

  if (prefersReducedMotion && reducedMotionFallback) {
    return (
      <section ref={rootRef} aria-label={label} data-depth-camera-scene data-reduced-motion className={className} style={style} {...props}>
        {reducedMotionFallback}
      </section>
    );
  }

  return (
    <section
      ref={rootRef}
      aria-label={label}
      data-depth-camera-scene
      data-ready={ready || undefined}
      data-fallback={failed || undefined}
      className={cn("relative isolate", className)}
      style={{ minHeight: `${Math.max(1, scrollScreens) * 100}svh`, ...style }}
      onPointerMove={handlePointerMove}
      onPointerLeave={handlePointerLeave}
      {...props}
    >
      <div ref={stageRef} className={cn("sticky top-0 h-svh overflow-hidden bg-black", stageClassName)}>
        <picture className={cn("absolute inset-0 z-0 block transition-opacity duration-700", ready && !failed ? "opacity-0" : "opacity-100")}>
          {mobilePoster ? <source media={`(max-width: ${mobileBreakpoint - 0.02}px)`} srcSet={mobilePoster} /> : null}
          <img alt="" src={poster} className="size-full object-cover" decoding="async" fetchPriority="high" />
        </picture>
        <canvas ref={backCanvasRef} aria-hidden className={cn("absolute inset-0 z-10 size-full origin-center transition-opacity duration-500 will-change-[filter,transform]", ready && !failed ? "opacity-100" : "opacity-0")} />
        {persistentBackdrop ? (
          <div
            aria-hidden
            className={cn(
              "pointer-events-none absolute inset-0 z-[15] transition-opacity duration-500",
              ready && !failed ? "opacity-100" : "opacity-0",
            )}
          >
            {persistentBackdrop}
          </div>
        ) : null}
        <div className="pointer-events-none absolute inset-0 z-20">
          {renderOverlay(backOverlay, visibleProgress)}
        </div>
        <canvas ref={frontCanvasRef} aria-hidden className={cn("pointer-events-none absolute inset-0 z-30 size-full transition-opacity duration-500", ready && !failed ? "opacity-100" : "opacity-0")} />
        <div className="pointer-events-none absolute inset-0 z-40">
          {renderOverlay(frontOverlay, visibleProgress)}
        </div>
      </div>
    </section>
  );
}

"use client";

import * as React from "react";
import { motion, type MotionValue, useTransform } from "motion/react";

import { cn } from "@/lib/utils";
import { clamp01 } from "@/components/experience/experience-runtime";

export type HorizontalTrackMetrics = {
  distance: number;
  trackWidth: number;
  viewportHeight: number;
  viewportWidth: number;
};

export type HorizontalTrackProps = Omit<React.ComponentProps<"div">, "children"> & {
  children: React.ReactNode;
  itemClassName?: string | ((index: number) => string | undefined);
  label: string;
  onMetricsChange?: (metrics: HorizontalTrackMetrics) => void;
  progress: MotionValue<number>;
  progressClassName?: string;
  progressIndicatorClassName?: string;
  /** Custom item counter, e.g. `(current, total) => \`${current} of ${total}\``. Defaults to "2 / 5". */
  renderCounter?: (current: number, total: number) => React.ReactNode;
  showProgress?: boolean;
  trackClassName?: string;
};

function sameMetrics(left: HorizontalTrackMetrics, right: HorizontalTrackMetrics) {
  return left.distance === right.distance
    && left.trackWidth === right.trackWidth
    && left.viewportHeight === right.viewportHeight
    && left.viewportWidth === right.viewportWidth;
}

/**
 * A measured horizontal track controlled by an external normalized progress.
 * It owns no sticky section or scroll listener, so it can live inside another
 * timeline, a 2.5D stage, a carousel controller, or a standalone composition.
 */
export function HorizontalTrack({
  children,
  className,
  itemClassName,
  label,
  onMetricsChange,
  progress,
  progressClassName,
  progressIndicatorClassName,
  renderCounter,
  showProgress = true,
  style,
  trackClassName,
  ...props
}: HorizontalTrackProps) {
  const viewportRef = React.useRef<HTMLDivElement>(null);
  const trackRef = React.useRef<HTMLDivElement>(null);
  const metricsRef = React.useRef<HorizontalTrackMetrics>({
    distance: 0,
    trackWidth: 0,
    viewportHeight: 0,
    viewportWidth: 0,
  });
  const items = React.Children.toArray(children);
  const [distance, setDistance] = React.useState(0);
  const x = useTransform(progress, [0, 1], [0, -distance], { clamp: true });
  const progressScale = useTransform(progress, (value) => clamp01(value));

  React.useEffect(() => {
    const viewport = viewportRef.current;
    const track = trackRef.current;
    if (!viewport || !track) return;

    const measure = () => {
      const next: HorizontalTrackMetrics = {
        distance: Math.max(0, track.scrollWidth - viewport.clientWidth),
        trackWidth: track.scrollWidth,
        viewportHeight: viewport.clientHeight,
        viewportWidth: viewport.clientWidth,
      };
      if (sameMetrics(metricsRef.current, next)) return;
      metricsRef.current = next;
      setDistance(next.distance);
      onMetricsChange?.(next);
    };

    const observer = new ResizeObserver(measure);
    observer.observe(viewport);
    observer.observe(track);
    measure();
    return () => observer.disconnect();
  }, [items.length, onMetricsChange]);

  return (
    <div
      ref={viewportRef}
      data-horizontal-track-viewport
      className={cn("relative flex h-full w-full items-center overflow-hidden", className)}
      style={style}
      {...props}
    >
      <motion.div
        ref={trackRef}
        role="list"
        aria-label={label}
        data-horizontal-track
        className={cn(
          "flex w-max items-stretch gap-[clamp(1rem,2.5vw,2.5rem)] px-[max(1.25rem,5vw)] will-change-transform",
          trackClassName,
        )}
        style={{ x }}
      >
        {items.map((child, index) => {
          const key = React.isValidElement(child) && child.key != null ? child.key : index;
          const resolvedItemClassName = typeof itemClassName === "function"
            ? itemClassName(index)
            : itemClassName;
          const counter = renderCounter?.(index + 1, items.length) ?? `${index + 1} / ${items.length}`;
          const counterLabel = typeof counter === "string" || typeof counter === "number"
            ? String(counter)
            : undefined;

          return (
            <div
              key={key}
              role="listitem"
              aria-label={counterLabel}
              data-horizontal-track-item={index}
              className={cn("w-[min(82vw,62rem)] shrink-0", resolvedItemClassName)}
            >
              {counterLabel === undefined ? <span className="sr-only">{counter}</span> : null}
              {child}
            </div>
          );
        })}
      </motion.div>

      {showProgress ? (
        <div
          aria-hidden
          className={cn(
            "absolute inset-x-[max(1.25rem,5vw)] bottom-6 h-px origin-left bg-current/20",
            progressClassName,
          )}
        >
          <motion.div
            className={cn("h-full origin-left bg-current", progressIndicatorClassName)}
            style={{ scaleX: progressScale }}
          />
        </div>
      ) : null}
    </div>
  );
}

"use client";

import * as React from "react";

const subscribeToHydration = () => () => undefined;

export function useHydrated() {
  return React.useSyncExternalStore(subscribeToHydration, () => true, () => false);
}

export function useMediaQuery(query: string, serverValue = false) {
  const subscribe = React.useCallback(
    (onChange: () => void) => {
      const media = window.matchMedia(query);
      media.addEventListener("change", onChange);
      return () => media.removeEventListener("change", onChange);
    },
    [query],
  );
  const getSnapshot = React.useCallback(() => window.matchMedia(query).matches, [query]);
  return React.useSyncExternalStore(subscribe, getSnapshot, () => serverValue);
}

/**
 * Hydration-safe reduced-motion preference: false on the server and during
 * hydration, then live. Replaces the repeated `mounted && useReducedMotion()`
 * pattern.
 */
export function usePrefersReducedMotion() {
  return useMediaQuery("(prefers-reduced-motion: reduce)");
}

/** True on touch-first devices; use to swap pointer effects for static or rail modes. */
export function useCoarsePointer() {
  return useMediaQuery("(pointer: coarse)");
}

/** True only when a hover-capable precise pointer is present. */
export function useFinePointer() {
  return useMediaQuery("(hover: hover) and (pointer: fine)");
}

export function clamp01(value: number) {
  return Math.min(1, Math.max(0, value));
}

export function mix(from: number, to: number, amount: number) {
  return from + (to - from) * amount;
}

export function damp(current: number, target: number, smoothing: number, deltaSeconds: number) {
  return mix(current, target, 1 - Math.exp(-Math.max(0.01, smoothing) * deltaSeconds));
}

/** Returns the frames sorted by `at`, reusing the input when it is already ordered. */
export function sortKeyframes<T extends { at: number }>(frames: T[]): T[] {
  for (let index = 1; index < frames.length; index += 1) {
    if (frames[index - 1]!.at > frames[index]!.at) {
      return [...frames].sort((left, right) => left.at - right.at);
    }
  }
  return frames;
}

export function resolveKeyframes<T extends { at: number }>(
  frames: T[],
  progress: number,
): { from: T; to: T; mix: number } {
  if (frames.length === 0) throw new Error("Experience keyframes cannot be empty.");
  const sorted = sortKeyframes(frames);
  if (progress <= sorted[0]!.at) return { from: sorted[0]!, to: sorted[0]!, mix: 0 };
  for (let index = 0; index < sorted.length - 1; index += 1) {
    const from = sorted[index]!;
    const to = sorted[index + 1]!;
    if (progress <= to.at) {
      const span = Math.max(0.0001, to.at - from.at);
      return { from, to, mix: clamp01((progress - from.at) / span) };
    }
  }
  const final = sorted.at(-1)!;
  return { from: final, to: final, mix: 0 };
}

export function supportsWebGL() {
  try {
    const canvas = document.createElement("canvas");
    return Boolean(
      canvas.getContext("webgl2", { failIfMajorPerformanceCaveat: true })
      || canvas.getContext("webgl", { failIfMajorPerformanceCaveat: true }),
    );
  } catch {
    return false;
  }
}

"use client";

import * as React from "react";
import { useMotionValue } from "motion/react";

/**
 * Stable `start start` → `end end` progress for pinned sections. It measures
 * the section itself, so progress remains monotonic all the way to the final
 * pixel and does not wrap when a sticky child releases.
 */
export function useElementScrollProgress(
  target: React.RefObject<HTMLElement | null>,
) {
  const progress = useMotionValue(0);

  React.useEffect(() => {
    const element = target.current;
    if (!element) return;
    let frame = 0;
    const measure = () => {
      const rect = element.getBoundingClientRect();
      const travel = Math.max(1, element.offsetHeight - window.innerHeight);
      progress.set(Math.max(0, Math.min(1, -rect.top / travel)));
    };
    const update = () => {
      cancelAnimationFrame(frame);
      frame = requestAnimationFrame(measure);
    };
    const resizeObserver = new ResizeObserver(update);
    resizeObserver.observe(element);
    window.addEventListener("scroll", update, { passive: true });
    window.addEventListener("resize", update, { passive: true });
    // Synchronous first measurement: consumers that render a bootstrap frame
    // before the first animation frame (e.g. a restored scroll position in a
    // background tab) already see the true progress.
    measure();
    return () => {
      cancelAnimationFrame(frame);
      resizeObserver.disconnect();
      window.removeEventListener("scroll", update);
      window.removeEventListener("resize", update);
    };
  }, [progress, target]);

  return progress;
}

# HorizontalTrack

Motor orizontal măsurat, controlat exclusiv printr-un `MotionValue<number>` extern. Componenta nu creează o secțiune sticky, nu citește scroll-ul global și nu impune un timeline. Poate fi montată într-o scenă 2.5D, într-un controller de carousel sau într-un alt recipe.

## Instalare

```bash
npx shadcn@latest add ./public/r/horizontal-track.json
```

## Exemplu controlat

```tsx
import { useTransform } from "motion/react"

import { HorizontalTrack } from "@/components/experience/horizontal-track"

const catalogProgress = useTransform(sceneProgress, [0.75, 0.96], [0, 1], {
  clamp: true,
})

<HorizontalTrack
  label="Catalog"
  progress={catalogProgress}
  itemClassName={(index) => index === 1 ? "w-[56vw]" : "w-[34vw]"}
  trackClassName="gap-4 px-[8vw]"
>
  {items.map((item) => <CatalogCard key={item.id} item={item} />)}
</HorizontalTrack>
```

`progress` este normalizat la `0…1`. Componenta măsoară `track.scrollWidth - viewport.clientWidth`, observă track-ul și viewport-ul cu `ResizeObserver` și recalculează automat după resize, font loading sau schimbarea dimensiunilor conținutului.

## Contract

- `HorizontalTrack` este o infrastructură controlată, nu o mecanică signature pe care Studio o propune singură clientului;
- parent-ul decide sursa progresului, sticky behavior-ul, timeline-ul și fallback-ul reduced-motion;
- `itemClassName` acceptă o clasă comună sau o funcție per index, deci item-urile pot avea lățimi diferite;
- `trackClassName` personalizează gap-ul, padding-ul și alinierea;
- `onMetricsChange` expune distanța, dimensiunea track-ului și viewport-ul pentru controllere externe;
- conținutul rămâne React semantic, iar ordinea DOM nu se schimbă.

Pentru varianta vertical-scroll completă folosește `HorizontalStoryRail`. Pentru catalogul final al unei scene cinematice, compune `HorizontalTrack` cu un controller de index/drag și animă intrarea întregului catalog prin timeline-ul scenei.

## QA

- testează `progress` la `0`, `0.5` și `1`;
- modifică lățimea viewport-ului după montare;
- verifică item-uri cu lățimi diferite și conținut încărcat lent;
- verifică faptul că primul și ultimul item se așază complet;
- parent-ul trebuie să ofere fallback normal pentru touch și `prefers-reduced-motion`;
- nu transforma acest building block într-un carousel fără controale, drag/swipe și tastatură.

"use client";

import * as React from "react";
import * as THREE from "three";

import { supportsWebGL } from "@/components/experience/experience-runtime";

export type WebGLStageContext = {
  renderer: THREE.WebGLRenderer;
  stage: HTMLElement;
  canvas: HTMLCanvasElement;
  /** Flip the stage to ready once async assets are decoded and the first frame can show. */
  markReady: () => void;
  /** Flip the stage to failed (poster/fallback becomes visible). */
  markFailed: () => void;
  /** True after the stage effect has been cleaned up; guard async callbacks with it. */
  isDisposed: () => boolean;
  /** Re-run the resize pass — call after async assets load so size-dependent caps apply. */
  requestResize: () => void;
};

export type WebGLStageHandle = {
  /** Runs every animation frame while the stage is on screen, the tab is visible and the context is alive. */
  onFrame?: (deltaSeconds: number, time: number) => void;
  /** Runs after the renderer resized; update cameras, uniforms and derived scales here. */
  onResize?: (width: number, height: number) => void;
  /** Optional extra cap on device pixel ratio for a given stage size (e.g. never supersample past the source texture). */
  getDpr?: (width: number, height: number) => number;
  /** Dispose geometries, materials and textures created in `create`; the renderer itself is disposed by the hook. */
  dispose?: () => void;
};

export type WebGLStageOptions = {
  stageRef: React.RefObject<HTMLElement | null>;
  canvasRef: React.RefObject<HTMLCanvasElement | null>;
  /** false keeps the stage fully inert — use it for reduced-motion / coarse-pointer static modes. */
  enabled: boolean;
  maxDpr?: number;
  antialias?: boolean;
  alpha?: boolean;
  /** Request a stencil buffer (three defaults it off since r163); needed for aperture/mask scenes. */
  stencil?: boolean;
  /**
   * Serialize every visual prop that must rebuild the scene into this string.
   * Array or callback identity never triggers a rebuild, so inline props stay safe.
   */
  signature?: string;
  /** Root margin for the offscreen pause observer. */
  rootMargin?: string;
  /** Build the scene. Reads props freely (latest values are visible via closure on each rebuild). */
  create: (context: WebGLStageContext) => WebGLStageHandle | void;
};

/**
 * Shared WebGL lifecycle for experience stages: renderer with capped DPR,
 * resize + offscreen observers, a visibility-gated animation loop, context-loss
 * pause with context-restore recovery, and full disposal. Components own only
 * their scene graph and per-frame logic.
 */
export function useWebGLStage({
  alpha = false,
  antialias = false,
  canvasRef,
  create,
  enabled,
  maxDpr = 1.6,
  rootMargin = "20% 0px",
  signature,
  stageRef,
  stencil = false,
}: WebGLStageOptions) {
  const [ready, setReady] = React.useState(false);
  const [failed, setFailed] = React.useState(false);
  const createRef = React.useRef(create);
  React.useInsertionEffect(() => {
    createRef.current = create;
  });

  React.useEffect(() => {
    const stage = stageRef.current;
    const canvas = canvasRef.current;
    if (!stage || !canvas || !enabled) return;
    if (!supportsWebGL()) {
      const timer = window.setTimeout(() => setFailed(true), 0);
      return () => window.clearTimeout(timer);
    }

    let disposed = false;
    let frame = 0;
    let previous = performance.now();
    let contextAlive = true;
    let lossTimer = 0;
    let onScreen = true;

    const renderer = new THREE.WebGLRenderer({ canvas, antialias, alpha, stencil, powerPreference: "high-performance" });
    renderer.outputColorSpace = THREE.SRGBColorSpace;
    renderer.setPixelRatio(Math.min(window.devicePixelRatio || 1, maxDpr));

    let handle: WebGLStageHandle = {};
    const resize = () => {
      const width = Math.max(1, stage.clientWidth);
      const height = Math.max(1, stage.clientHeight);
      const extraCap = handle.getDpr?.(width, height) ?? Number.POSITIVE_INFINITY;
      renderer.setPixelRatio(Math.max(0.5, Math.min(window.devicePixelRatio || 1, maxDpr, extraCap)));
      renderer.setSize(width, height, false);
      handle.onResize?.(width, height);
    };
    const context: WebGLStageContext = {
      renderer,
      stage,
      canvas,
      markReady: () => {
        if (!disposed) setReady(true);
      },
      markFailed: () => {
        if (!disposed) setFailed(true);
      },
      isDisposed: () => disposed,
      requestResize: () => {
        if (!disposed) resize();
      },
    };
    handle = createRef.current(context) ?? {};
    const resizeObserver = new ResizeObserver(resize);
    resizeObserver.observe(stage);

    const intersectionObserver = new IntersectionObserver(
      ([entry]) => {
        onScreen = Boolean(entry?.isIntersecting);
      },
      { rootMargin },
    );
    intersectionObserver.observe(stage);

    // preventDefault opts into restoration; Three re-uploads retained resources
    // on the next render after the context returns. Only a loss that never
    // restores becomes a visible failure.
    const contextLost = (event: Event) => {
      event.preventDefault();
      contextAlive = false;
      window.clearTimeout(lossTimer);
      lossTimer = window.setTimeout(() => {
        if (!disposed && !contextAlive) setFailed(true);
      }, 2500);
    };
    const contextRestored = () => {
      window.clearTimeout(lossTimer);
      contextAlive = true;
      if (disposed) return;
      setFailed(false);
      resize();
    };
    canvas.addEventListener("webglcontextlost", contextLost);
    canvas.addEventListener("webglcontextrestored", contextRestored);

    const render = (time: number) => {
      if (disposed) return;
      const delta = Math.min(0.05, Math.max(0.001, (time - previous) / 1000));
      previous = time;
      if (contextAlive && onScreen && document.visibilityState === "visible") {
        handle.onFrame?.(delta, time);
      }
      frame = requestAnimationFrame(render);
    };

    resize();
    frame = requestAnimationFrame(render);

    return () => {
      disposed = true;
      cancelAnimationFrame(frame);
      window.clearTimeout(lossTimer);
      resizeObserver.disconnect();
      intersectionObserver.disconnect();
      canvas.removeEventListener("webglcontextlost", contextLost);
      canvas.removeEventListener("webglcontextrestored", contextRestored);
      handle.dispose?.();
      renderer.dispose();
    };
  }, [alpha, antialias, canvasRef, enabled, maxDpr, rootMargin, signature, stageRef, stencil]);

  return { ready, failed };
}
